const trades = $input.all().map(i => i.json);
const total = trades.length;
const wins = trades.filter(t => t.outcome === 'WIN').length;
const losses = trades.filter(t => t.outcome === 'LOSS').length;
const winRate = total > 0 ? Math.round((wins / total) * 10000) / 100 : 0;

const winTrades = trades.filter(t => t.outcome === 'WIN');
const lossTrades = trades.filter(t => t.outcome === 'LOSS');
const avgWin = winTrades.length > 0
  ? Math.round(winTrades.reduce((s, t) => s + parseFloat(t.pnl_pct || 0), 0) / winTrades.length * 100) / 100 : 0;
const avgLoss = lossTrades.length > 0
  ? Math.round(lossTrades.reduce((s, t) => s + parseFloat(t.pnl_pct || 0), 0) / lossTrades.length * 100) / 100 : 0;
const totalPnl = Math.round(trades.reduce((s, t) => s + parseFloat(t.pnl_amount || 0), 0) * 100) / 100;

const byConfidence = {};
for (const t of trades) {
  const conf = parseInt(t.confidence);
  if (!conf) continue;
  const range = conf >= 80 ? '80+' : conf >= 70 ? '70-79' : '60-69';
  if (!byConfidence[range]) byConfidence[range] = { wins: 0, total: 0 };
  byConfidence[range].total++;
  if (t.outcome === 'WIN') byConfidence[range].wins++;
}

const tagCounts = {};
for (const t of trades) {
  try {
    const tags = typeof t.feedback_tags === 'string' ? JSON.parse(t.feedback_tags) : (t.feedback_tags || []);
    for (const tag of tags) { tagCounts[tag] = (tagCounts[tag] || 0) + 1; }
  } catch(e) {}
}

const byTicker = {};
for (const t of trades) {
  if (!byTicker[t.ticker]) byTicker[t.ticker] = { wins: 0, total: 0, pnl: 0 };
  byTicker[t.ticker].total++;
  byTicker[t.ticker].pnl += parseFloat(t.pnl_amount) || 0;
  if (t.outcome === 'WIN') byTicker[t.ticker].wins++;
}

return [{ json: { trades, stats: { total, wins, losses, winRate, avgWin, avgLoss, totalPnl, byConfidence, tagCounts, byTicker } } }];

