const response = $input.first().json;
const stats = $('Calculate Stats').first().json.stats;

let content = response.choices?.[0]?.message?.content || '';
content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  return [{ json: { error: true, response: 'AI returned invalid JSON during review. Try again.' } }];
}

return [{
  json: {
    insights: parsed.insights || [],
    adjustments: parsed.adjustments || {},
    summary: parsed.summary || '',
    win_rate: stats.winRate,
    trades_analyzed: stats.total,
    week_start: new Date(Date.now() - new Date().getDay() * 86400000).toISOString().split('T')[0],
  }
}];

const data = $('Validate Review').first().json;

if (data.error) return [{ json: { response: data.response } }];

let response = `WEEKLY REVIEW COMPLETE\n\n`;
response += `Win rate: ${data.win_rate}% | Trades analyzed: ${data.trades_analyzed}\n\n`;
response += `KEY INSIGHTS:\n`;
const insights = data.insights || [];
insights.forEach((insight, i) => { response += `${i + 1}. ${insight}\n`; });
response += `\nSUMMARY: ${data.summary}`;

return [{ json: { response } }];
